const raw = $input.first().json.output[0].content[0].text;
const parsed = JSON.parse(raw);
return { json: parsed };

const mammoth = require('mammoth');
const binaryData = await this.helpers.getBinaryDataBuffer(0, 'file0');

const result = await mammoth.extractRawText({ buffer: binaryData });

return { json: { text: result.value } };

let cvText = '';

try {
  cvText = $('Parse PDF CV').first().json.text;
} catch (e) {
  // PDF node didn't run
}

if (!cvText) {
  try {
    cvText = $('Parse DOCX CV').first().json.text;
  } catch (e) {
    // DOCX node didn't run either
  }
}

const sheetData = $('Read Job Requirements').first().json;

return {
  json: {
    ...sheetData,
    cv_text: cvText
  }
};

const item = $input.first();

// 1. Check if file exists
if (!item.binary || !item.binary.file0) {
  throw new Error('No file attached. Please send a CV file (PDF or DOCX).');
}

// 2. Check if job_id exists
if (!item.json.body?.job_id) {
  throw new Error('Missing job_id. Please include job_id in your request.');
}

// 3. Check file format
const fileName = item.binary.file0.fileName || '';
const extension = fileName.split('.').pop().toLowerCase();

if (!['pdf', 'docx'].includes(extension)) {
  throw new Error(`Unsupported file format: .${extension}. Only PDF and DOCX are accepted.`);
}

// 4. All checks passed — forward data
return [item];

const candidate = $input.first().json.candidate_name;
const jobId = $input.first().json.job_id;

// Create a unique key
const key = `${candidate}_${jobId}`.toLowerCase().replace(/\s+/g, '_');

// Check against static variable (persists across executions)
const seen = $getWorkflowStaticData('global');

if (seen[key]) {
  throw new Error(`Duplicate: ${candidate} already screened for ${jobId}`);
}

// Mark as seen
seen[key] = new Date().toISOString();

// Pass data through
return $input.all();
